'use strict';
const fs = require('fs');
const path = require('path');

function processFeature(config) {
  if (!config || !config.name) throw new Error('name required');
  return { processed: true, name: config.name, ts: Date.now() };
}

function validateFeature(feature) {
  return feature.processed === true && typeof feature.name === 'string';
}

module.exports = { processFeature, validateFeature };

const { test, assert } = require('node:test');

let mod;
try { mod = require('./rf-feature-handler.cjs'); } catch (e) { mod = null; }

test('processFeature returns processed object', () => {
  assert.ok(mod, 'module should load');
  const result = mod.processFeature({ name: 'test' });
  assert.ok(result.processed);
  assert.strictEqual(result.name, 'test');
});

test('validateFeature checks processed flag', () => {
  assert.ok(mod, 'module should load');
  assert.ok(mod.validateFeature({ processed: true, name: 'x' }));
  assert.ok(!mod.validateFeature({ processed: false, name: 'x' }));
});

'use strict';
function validateConfig(config) {
  const errors = [];
  if (!config.env) errors.push('missing env');
  if (!config.port || config.port < 1) errors.push('invalid port');
  if (!config.host) errors.push('missing host');
  return { valid: errors.length === 0, errors };
}
function mergeDefaults(config, defaults) {
  return { ...defaults, ...config };
}
module.exports = { validateConfig, mergeDefaults };

'use strict';
const transitions = {
  idle: ['running'],
  running: ['paused', 'completed', 'failed'],
  paused: ['running', 'cancelled'],
  failed: ['retrying'],
  retrying: ['running', 'failed'],
  completed: [],
  cancelled: []
};
function createState(initialState) {
  let current = initialState || 'idle';
  return {
    transition(to) {
      if (!transitions[current] || !transitions[current].includes(to)) {
        throw new Error('invalid transition: ' + current + ' -> ' + to);
      }
      current = to;
      return current;
    },
    state() { return current; },
    canTransition(to) { return (transitions[current] || []).includes(to); }
  };
}
module.exports = { createState, transitions };

'use strict';
function identity(x) { return x; }
function noop() {}
function constant(v) { return () => v; }
module.exports = { identity, noop, constant };

'use strict';
function overlapFeature(input) {
  return { result: input * 2 };
}
module.exports = { overlapFeature };
